// One output item per PDF attachment, with its sha256 + metadata.
const crypto = require('crypto');
const out = [];
for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  for (const key of Object.keys(bin)) {
    if (!key.startsWith('attachment_')) continue;
    const meta = bin[key];
    if ((meta.mimeType || '').indexOf('pdf') === -1 && !(meta.fileName||'').toLowerCase().endsWith('.pdf')) continue;
    const buf = await this.helpers.getBinaryDataBuffer(i, key);
    const hash = crypto.createHash('sha256').update(buf).digest('hex');
    out.push({ json: {
        gmail_message_id: items[i].json.id,
        thread_id: items[i].json.threadId,
        filename: meta.fileName || (hash + '.pdf'),
        mime: meta.mimeType || 'application/pdf',
        hash: hash,
        storage_path: hash + '.pdf'
      }, binary: { data: meta }, pairedItem: { item: i } });
  }
}
return out;
